    expect(interpolateDeep(input, CONTEXT)).toEqual({
      header: {
        title: 'Abastecimento',
        subtitle: 'R$ 7.716,00',
      },
    });
  });

  it('interpolates strings in arrays', () => {
    const input = ['{{product.name}}', '{{product.key}}'];
    expect(interpolateDeep(input, CONTEXT)).toEqual([
      'Abastecimento',
      'abastecimento',
    ]);
  });

  it('preserves non-string primitives', () => {
    const input = {
      count: 42,
      active: true,
      empty: null,
      text: '{{product.name}}',
    };
    expect(interpolateDeep(input, CONTEXT)).toEqual({
      count: 42,
      active: true,
      empty: null,
      text: 'Abastecimento',
    });
  });

  it('handles deeply nested mixed structures', () => {
    const input = {
      body: [
